import re
text = open("_response.md").read()
lines = text.split("\n")
in_block = False
start_line = 0
buf = []
flagged = []

# Node label patterns: [..], [(..)], [[..]], {..}, (..)
# We check inside node labels and inside |".."| edge labels.
breaking = set('():;/<>"')  # parens, colon, semicolon, slash, angle, quote
# curly braces are breaking ONLY when used as a label delimiter incorrectly; {Shard router} is a decision node (valid)

def check_line(absn, ln):
    stripped = ln.strip()
    if stripped.startswith("classDef") or stripped.startswith("flowchart") or stripped.startswith("subgraph") or stripped=="end":
        # classDef lines legitimately contain colons/# - not labels
        # subgraph quoted labels are fine
        return
    # Extract node label contents: text inside [ ], [( )], [[ ]], { }
    # Find all bracketed label bodies
    labels = []
    # [[ ... ]]
    for m in re.finditer(r'\[\[(.*?)\]\]', ln):
        labels.append(('[[]]', m.group(1)))
    # remove [[ ]] then [( )]
    tmp = re.sub(r'\[\[.*?\]\]','',ln)
    for m in re.finditer(r'\[\((.*?)\)\]', tmp):
        labels.append(('[()]', m.group(1)))
    tmp2 = re.sub(r'\[\(.*?\)\]','',tmp)
    # plain [ ]
    for m in re.finditer(r'\[([^\[\]]*?)\]', tmp2):
        labels.append(('[]', m.group(1)))
    # decision { }
    for m in re.finditer(r'\{([^{}]*?)\}', ln):
        labels.append(('{}', m.group(1)))
    # edge labels |"..."| or |...|
    for m in re.finditer(r'\|"?([^|]*?)"?\|', ln):
        labels.append(('edge', m.group(1)))
    for kind, lab in labels:
        # For edge labels they're quoted, so breaking chars are safe inside quotes
        bad = [c for c in lab if c in breaking]
        if bad:
            flagged.append((absn, kind, lab, set(bad)))

for n, ln in enumerate(lines, 1):
    if ln.strip().startswith("```mermaid"):
        in_block = True; start_line = n+1; buf=[]; continue
    if in_block and ln.strip() == "```":
        in_block = False; continue
    if in_block:
        check_line(n, ln)

print("FLAGGED LABEL/EDGE CONTENTS WITH POTENTIAL BREAKING CHARS:")
if not flagged:
    print("  NONE")
for absn, kind, lab, bad in flagged:
    print(f"  line {absn} [{kind}] '{lab}'  -> chars {bad}")
EOF

